import React, { useState, useEffect } from "react";
import axios from "axios";

function Dashboard() {
    const [file, setFile] = useState(null);
    const [resumes, setResumes] = useState([]);
    const [result, setResult] = useState([]);

    const token = localStorage.getItem("token");

    // ✅ Fetch resumes on load
    useEffect(() => {
        fetchResumes();
    }, []);

    const fetchResumes = async () => {
        try {
            const res = await axios.get("http://localhost:8080/resumes", {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            });

            setResumes(res.data);
        } catch (err) {
            console.error("Error fetching resumes", err);
        }
    };

    // ✅ Upload Resume
    const handleUpload = async () => {
        if (!file) return alert("Select file first");

        const formData = new FormData();
        formData.append("file", file);
        formData.append("name", "Test User");
        formData.append("email", "test@gmail.com");
        formData.append("skills", "java spring boot");
        formData.append("experience", 2);

        try {
            await axios.post(
                "http://localhost:8080/resumes/upload",
                formData,
                {
                    headers: {
                        Authorization: `Bearer ${token}`,
                        "Content-Type": "multipart/form-data"
                    }
                }
            );

            alert("Uploaded!");
            fetchResumes(); // ✅ refresh list
        } catch (err) {
            console.error(err);
            alert("Upload failed");
        }
    };

    // ✅ Match API
    const getMatches = async () => {
        try {
            const res = await axios.get(
                "http://localhost:8080/resumes/match?skill=java&experience=1",
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            );

            setResult(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Delete
    const handleDelete = async (id) => {
        try {
            await axios.delete(`http://localhost:8080/resumes/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });

            alert("Deleted!");
            fetchResumes(); // ✅ FIXED
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Download
    const handleDownload = async (id) => {
        try {
            const res = await axios.get(
                `http://localhost:8080/resumes/download/${id}`,
                {
                    headers: { Authorization: `Bearer ${token}` },
                    responseType: "blob"
                }
            );

            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement("a");
            link.href = url;
            link.setAttribute("download", "resume.pdf");
            document.body.appendChild(link);
            link.click();
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Logout
    const handleLogout = () => {
        localStorage.removeItem("token");
        window.location.reload();
    };

    return (
        <div style={{ padding: 20 }}>
            <h2>Dashboard</h2>

            <button onClick={handleLogout}>Logout</button>

            <hr />

            {/* ✅ Upload Section */}
            <h3>Add Resume</h3>
            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />
            <button onClick={handleUpload}>Upload Resume</button>

            <hr />

            {/* ✅ Resume List */}
            <h3>Your Resumes</h3>

            {resumes.length === 0 ? (
                <p>No resumes found</p>
            ) : (
                <ul>
                    {resumes.map((r) => (
                        <li key={r.id}>
                            <b>{r.name}</b> - {r.skills} ({r.experience} yrs)

                            <br />

                            <button onClick={() => handleDownload(r.id)}>Download</button>
                            <button onClick={() => handleDelete(r.id)}>Delete</button>
                        </li>
                    ))}
                </ul>
            )}

            <hr />

            {/* ✅ Match Section */}
            <h3>Find Matches</h3>
            <button onClick={getMatches}>Find Matches</button>

            <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(3, 1fr)",
                gap: "20px",
                marginTop: "20px"
            }}>
                {result.map((r, i) => (
                    <div key={i} style={{
                        border: "1px solid #ccc",
                        padding: "15px",
                        borderRadius: "10px"
                    }}>
                        <h3>{r?.summary?.name}</h3>
                        <p>Email: {r?.summary?.email}</p>
                        <p>Skills: {r?.summary?.skills}</p>
                        <p>Experience: {r?.summary?.experience}</p>
                        <p>Score: {r?.score}</p>

                        <button onClick={() => handleDownload(r.summary.id)}>Download</button>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Dashboard;
